#pragma once

#include <stddef.h>
#include <stdint.h>

/* The question pack travels embedded in the FAP binary as `const` arrays
 * stored in flash. The runtime reads them via pointer arithmetic — no SD
 * card lookup, no auxiliary install step.
 *
 * Definitions live in src/data/embedded_pack_{es,en}.c, which are
 * auto-generated by tools/build_pack.py and committed to the repo so the
 * FAP can be built on a clean checkout without running the Python pipeline.
 */

extern const uint8_t trivia_es_idx[];
extern const size_t trivia_es_idx_len;
extern const char trivia_es_tsv[];
extern const size_t trivia_es_tsv_len;

extern const uint8_t trivia_en_idx[];
extern const size_t trivia_en_idx_len;
extern const char trivia_en_tsv[];
extern const size_t trivia_en_tsv_len;
